export function parseArgs(argv) {
  const result = { _: [] }
  for (let index = 0; index < argv.length; index += 1) {
    const arg = argv[index]
    if (!arg.startsWith('--')) {
      result._.push(arg)
      continue
    }
    const keyEquals = arg.slice(2)
    let key
    if (arg.includes('=')) {
      key = keyEquals.slice(0, keyEquals.indexOf('='))
      result[key] = arg.slice(arg.indexOf('=') + 1)
      continue
    }
    key = keyEquals
    if (key in result) {
      // Key already has a value, treat as boolean flag
      result[key] = true
      continue
    }
    // Check if next arg is a flag
    const nextArg = argv[index + 1]
    if (nextArg && nextArg.startsWith('--')) {
      // Next arg is a flag, so current key is a boolean
      result[key] = true
    } else {
      // Next arg is a value
      result[key] = nextArg
      index += 1
    }
  }
  return result
}
